// src/services/api.js
const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000/api";

const getAuthHeaders = () => {
    const savedUser = localStorage.getItem('user-session'); // Usamos tu AuthContext
    if (savedUser) {
        const { token } = JSON.parse(savedUser);
        return {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${token}`
        };
    }
    return { 'Content-Type': 'application/json' };
};

export const api = {
    // AUTH
    login: async (email, password) => {
        const response = await fetch(`${API_URL}/auth/login`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ correo: email, password })
        });
        if (!response.ok) {
            const error = await response.json();
            throw new Error(error.msg || "Error en el login");
        }
        return await response.json();
    },

    // LOCALES
    getLocalesVendedor: async (vendedorId) => {
        const res = await fetch(`${API_URL}/locales/vendedor/${vendedorId}`, {
            headers: getAuthHeaders()
        });
        return await res.json();
    },

    crearLocal: async (data) => {
        const res = await fetch(`${API_URL}/locales`, {
            method: 'POST',
            headers: getAuthHeaders(),
            body: JSON.stringify(data) // El backend espera { nombre, direccion, vendedorId, lng, lat }
        });
        return await res.json();
    },

    // OFERTAS
    getOfertas: async () => {
        // Nueva ruta para que el cliente vea todas las ofertas de la DB
        const res = await fetch(`${API_URL}/ofertas`); 
        return await res.json();
    },

    crearOferta: async (formData) => {
        const savedUser = localStorage.getItem('user-session');
        const token = savedUser ? JSON.parse(savedUser).token : '';
        const res = await fetch(`${API_URL}/ofertas`, {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${token}` }, // Sin Content-Type para FormData
            body: formData 
        });
        return await res.json();
    }
};
